using namespace std;

bool isPrime(long long num) {
    if (num <= 1) return false;
    if (num == 2) return true;
    if (num % 2 == 0) return false;
    for (long long i = 3; i * i <= num; i += 2) {
        if (num % i == 0) return false;
    }
    return true;
}

long long solve(std::vector<long long> nums) {
    int n = nums.size();
    if (n == 1) return 0;

    unordered_map<long long, vector<int>> primeToIndices;
    for (int i = 0; i < n; ++i) {
        long long num = nums[i];
        if (isPrime(num)) {
            primeToIndices[num].push_back(i);
        }
    }

    unordered_map<long long, vector<int>> factorToIndices;
    for (int i = 0; i < n; ++i) {
        long long num = nums[i];
        if (num == 1) continue;
        for (const auto& entry : primeToIndices) {
            long long p = entry.first;
            if (num % p == 0) {
                factorToIndices[p].push_back(i);
            }
        }
    }

    vector<int> dist(n, INT_MAX);
    dist[0] = 0;
    queue<int> q;
    q.push(0);

    while (!q.empty()) {
        int current = q.front();
        q.pop();

        // Move to adjacent indices
        vector<int> neighbors;
        if (current > 0) neighbors.push_back(current - 1);
        if (current < n - 1) neighbors.push_back(current + 1);

        for (int neighbor : neighbors) {
            if (dist[neighbor] > dist[current] + 1) {
                dist[neighbor] = dist[current] + 1;
